230	// Cleanup scans the configured DDx temp worktree root, consults the project
231	// run-state file and git worktree registry, and conservatively removes stale
232	// DDx-owned temp resources.
233	func (m *ExecutionCleanupManager) Cleanup(ctx context.Context) (ExecutionCleanupSummary, error) {
234		summary := ExecutionCleanupSummary{
235			ProjectRoot: m.ProjectRoot,
236			TempRoot:    m.tempRoot(),
237		}
238		if ctx != nil {
239			if err := ctx.Err(); err != nil {
240				return summary, err
241			}
242		}
243		if summary.TempRoot == "" {
244			summary.TempRoot = executionCleanupTempRoot(m.ProjectRoot)
245		}
246		if summary.TempRoot == "" {
247			return summary, errors.New("execution cleanup: temp root is empty")
248		}
249		if m.ProjectRoot == "" {
250			return summary, errors.New("execution cleanup: project root is empty")
251		}
252		now := time.Now
253		if m.Now != nil {
254			now = m.Now
255		}
256		probe := m.Probe
257		if probe == nil {
258			probe = defaultExecutionCleanupLivenessProbe{}
259		}
260	
261		registered := map[string]struct{}{}
262		liveRunStates := map[string]struct{}{}
263		if m.GitOps != nil {
264			paths, err := m.GitOps.WorktreeList(m.ProjectRoot)
265			if err != nil {
266				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
267					Path:    m.ProjectRoot,
268					Class:   "git_worktree_list",
269					Message: err.Error(),
270				})
271			} else {
272				for _, p := range paths {
273					registered[filepath.Clean(p)] = struct{}{}
274				}
275			}
276		}
277		if ctx != nil {
278			if err := ctx.Err(); err != nil {
279				return summary, err
280			}
281		}
282	
283		runStates, runStateErr := ReadRunStates(m.ProjectRoot)
284		if runStateErr != nil {
285			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
286				Path:    runStateDirPath(m.ProjectRoot),
287				Class:   "run_state_read",
288				Message: runStateErr.Error(),
289			})
290		}
291		if ctx != nil {
292			if err := ctx.Err(); err != nil {
293				return summary, err
294			}
295		}
296	
297		entries, err := os.ReadDir(summary.TempRoot)
298		if err != nil {
299			return summary, fmt.Errorf("execution cleanup: read temp root: %w", err)
300		}
301		for _, entry := range entries {
302			if !entry.IsDir() {
303				continue
304			}
305			if ctx != nil {
306				if err := ctx.Err(); err != nil {
307					return summary, err
308				}
309			}
310			if !hasAnyPrefix(entry.Name(), executionAttemptDirPrefixes()) {
311				continue
312			}
313			summary.ScannedTempDirs++
314			path := filepath.Join(summary.TempRoot, entry.Name())
315	
316			meta, metaErr := ReadExecutionCleanupMetadata(path)
317			missingMetadata := false
318			if metaErr != nil {
319				if errors.Is(metaErr, os.ErrNotExist) {
320					missingMetadata = true
321					meta = ExecutionCleanupMetadata{
322						ProjectRoot:  m.ProjectRoot,
323						WorktreePath: path,
324					}
325				} else {
326					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
327						Path:    path,
328						Class:   "metadata_read",
329						Message: metaErr.Error(),
330					})
331					continue
332				}
333			}
334			candidateRunStates := runStates
335			ownershipMismatch := meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot)
336			if ownershipMismatch {
337				candidateRunStates = m.runStatesForMetadata(meta, runStates, &summary)
338			}
339	
340			matchedRunState := matchingRunStateForMeta(candidateRunStates, meta)
341			live, reason := probe.IsLive(meta, matchedRunState, now())
342			if live {
343				if matchedRunState != nil {
344					liveRunStates[runStateLiveKey(*matchedRunState)] = struct{}{}
345				}
346				class := "preserved_temp_dir"
347				if isLiveAttemptPreservation(reason) {
348					class = "preserved_live_attempt"
349				}

350				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
351					Path:    path,
352					Class:   class,
353					Message: reason,
354				})
355				continue
356			}
357			if ownershipMismatch {
358				if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, path) {
359					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
360						Path:    path,
361						Class:   "ownership_mismatch",
362						Message: fmt.Sprintf("metadata project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
363					})
364					continue
365				}
366				if m.isRegisteredWorktree(meta.ProjectRoot, path, &summary) {
367					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
368						Path:    path,
369						Class:   "preserved_foreign_registered_worktree",
370						Message: "foreign project worktree is still registered",
371					})
372					continue
373				}
374			}
375	
376			if _, ok := registered[filepath.Clean(path)]; ok {
377				if missingMetadata {
378					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
379						Path:    path,
380						Class:   "registered_missing_metadata",
381						Message: "registered DDx worktree has no cleanup metadata; preserving",
382					})
383					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
384						Path:    path,
385						Class:   "preserved_registered_missing_metadata",
386						Message: "registered worktree without cleanup metadata",
387					})
388					continue
389				}
390				if m.GitOps == nil {
391					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
392						Path:     path,
393						Class:    "registered_worktree",
394						Message:  "no git ops available to remove registered worktree",
395						Blocking: true,
396					})
397					continue
398				}
399				reclaimedBytes, reclaimedInodes, measureErr := measureTreeWithContext(ctx, path)
400				if measureErr != nil {
401					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
402						Path:    path,
403						Class:   "measure_tree",
404						Message: measureErr.Error(),
405					})
406				}
407				if !m.DryRun {
408					if err := m.GitOps.WorktreeRemove(m.ProjectRoot, path); err != nil {
409						summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
410							Path:     path,
411							Class:    "registered_worktree_remove",
412							Message:  err.Error(),
413							Blocking: true,
414						})
415						continue
416					}
417				}
418				summary.RemovedRegisteredWorktrees++
419				summary.BytesReclaimed += reclaimedBytes
420				summary.InodesReclaimed += reclaimedInodes
421				class := "removed_registered_worktree"
422				if m.DryRun {
423					class = "would_remove_registered_worktree"
424				}
425				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
426					Path:    path,
427					Class:   class,
428					Message: reason,
429					Bytes:   reclaimedBytes,
430					Inodes:  reclaimedInodes,
431				})
432				continue
433			}
434	
435			reclaimedBytes, reclaimedInodes, measureErr := measureTreeWithContext(ctx, path)
436			if measureErr != nil {
437				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
438					Path:    path,
439					Class:   "measure_tree",
440					Message: measureErr.Error(),
441				})
442			}
443			if !m.DryRun {
444				if err := os.RemoveAll(path); err != nil {
445					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
446						Path:     path,
447						Class:    "unregistered_temp_dir_remove",
448						Message:  err.Error(),
449						Blocking: false,
450					})
451					continue
452				}
453			}
454			summary.RemovedUnregisteredTempDirs++
455			summary.BytesReclaimed += reclaimedBytes
456			summary.InodesReclaimed += reclaimedInodes
457			class := "removed_unregistered_temp_dir"
458			if m.DryRun {
459				class = "would_remove_unregistered_temp_dir"
460			}
461			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
462				Path:    path,
463				Class:   class,
464				Message: reason,
465				Bytes:   reclaimedBytes,
466				Inodes:  reclaimedInodes,
467			})
468		}
469	
470		if err := m.cleanupScratchRoots(ctx, &summary, runStates, registered, probe, now()); err != nil {
471			return summary, err
472		}
473	
474		if m.GitOps != nil && summary.RemovedRegisteredWorktrees > 0 && !m.DryRun {
475			if err := m.GitOps.WorktreePrune(m.ProjectRoot); err != nil {
476				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
477					Path:    m.ProjectRoot,
478					Class:   "worktree_prune",
479					Message: err.Error(),
480				})
481			}
482		}
483	
484		// Stale run-state files are removed when they point at an execution
485		// resource that is no longer live.
486		for _, state := range runStates {
487			if _, ok := liveRunStates[runStateLiveKey(state)]; ok {
488				continue
489			}
490			if runStateWorktreeStillExists(state) {
491				continue
492			}
493			if removed, bytes := m.removeStaleRunState(state, &summary); removed {
494				summary.RemovedRunStateFiles++
495				summary.BytesReclaimed += bytes
496				summary.InodesReclaimed++
497			}
498		}
499	
500		if ctx != nil {
501			if err := ctx.Err(); err != nil {
502				return summary, err
503			}
504		}
505		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ExecuteBeadArtifactDir, "manifest.json", "result.json", &summary)
506		m.pruneEvidenceDirs(ctx, &summary, runStates, now())
507		if ctx != nil {
508			if err := ctx.Err(); err != nil {
509				return summary, err
510			}
511		}
512		m.pruneAgentLogs(ctx, &summary, runStates, now())
513		if ctx != nil {
514			if err := ctx.Err(); err != nil {
515				return summary, err
516			}
517		}
518		m.pruneWorkerDirs(ctx, &summary, now())
519		if ctx != nil {
520			if err := ctx.Err(); err != nil {
521				return summary, err
522			}
523		}
524		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ".ddx/runs", "record.json", "", &summary)
525		m.cleanupDurableLandedCandidateRefs(&summary)
526	
527		return summary, nil
528	}
