func TestExecutionCleanup_RemovesExpiredRunStateForDeadPID(t *testing.T) {
	projectRoot := setupExecutionCleanupProjectRoot(t)
	tempRoot := t.TempDir()
	now := time.Date(2026, 5, 21, 7, 15, 0, 0, time.UTC)
	deadPID := 4109595

	stalePath := filepath.Join(tempRoot, ExecuteBeadWtPrefix+"ddx-dead-20260521T071245-feb2ad20")
	writeExecutionCleanupCandidate(t, stalePath, ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		BeadID:       "ddx-test",
		AttemptID:    "20260521T071245-feb2ad20",
		WorktreePath: stalePath,
	}, map[string]string{"scratch.txt": "stale\n"})

	// Write an expired run-state for a dead PID
	// expires_at is in the past, refresh_at is in the past, PID is dead
	require.NoError(t, WriteRunState(projectRoot, RunState{
		BeadID:       "ddx-test",
		AttemptID:    "20260521T071245-feb2ad20",
		StartedAt:    now.Add(-5 * time.Minute),
		RefreshedAt:  now.Add(-3 * time.Minute),
