	mgr.TempRoot = tempRoot
	mgr.Now = func() time.Time { return now }

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	// The stale worktree should be removed
	assert.NoFileExists(t, stalePath)
	// The expired run-state file should be removed
	assert.Equal(t, int64(1), summary.RemovedRunStateFiles)
	// Verify the run-state is no longer in the system
	states, err := ReadRunStates(projectRoot)
	require.NoError(t, err)
	assert.Len(t, states, 0)
	// Verify the observation shows it was removed, not preserved
	assert.False(t, hasObservationClass(summary.Observations, "preserved_live_attempt"),
		"dead PID with expired lease should not be preserved as live attempt")
}

